const input = $input.first().json;
const chatInput = input.chatInput || input.message || '';
const sessionId = input.sessionId || 'default';
const profileMatch = chatInput.match(/\[PROFILE\]([^\[]+)/);
const profileStr = profileMatch ? profileMatch[1] : '';
const getField = (label) => {
  const re = new RegExp(label + '\\s*:\\s*([^|\\n]+?)(?=\\s*\\||\\n|$)', 'i');
  const m = profileStr.match(re);
  return m ? m[1].trim() : '';
};
const userName = getField('ชื่อ-นามสกุล') || 'คุณ';
const userGenderRaw = getField('เพศ').toLowerCase();
const userGender = userGenderRaw.includes('ชาย') || userGenderRaw === 'male' || userGenderRaw === 'm' ? 'male'
  : userGenderRaw.includes('หญิง') || userGenderRaw === 'female' || userGenderRaw === 'f' ? 'female' : 'unknown';
const femaleKeywords = ['ประจำเดือน','รอบเดือน','เมนส์','menstrual','menstruation','period','ตกขาว','มดลูก','ช่องคลอด','ตั้งครรภ์','ครรภ์','pregnant','ปวดท้องน้อยช่วงเมนส์'];
const maleKeywords = ['อัณฑะ','ลูกอัณฑะ','องคชาต','อวัยวะเพศชาย','prostate','testic'];
const genderMismatch = femaleKeywords.some(kw => chatInput.toLowerCase().includes(kw.toLowerCase())) && userGender === 'male';
const genderMismatchM = maleKeywords.some(kw => chatInput.toLowerCase().includes(kw.toLowerCase())) && userGender === 'female';
const conditions32 = ['ปวดศีรษะ','เวียนศีรษะ','มึนศีรษะ','ปวดข้อ','ปวดกล้ามเนื้อ','เมื่อย','ไข้','ไอ','เจ็บคอ','คัดจมูก','ภูมิแพ้','น้ำมูก','ปวดท้อง','ท้องเสีย','ท้องผูก','คลื่นไส้','อาเจียน','กรดไหลย้อน','ริดสีดวง','ผื่น','คัน','แพ้','กลาก','เกลื้อน','หิด','เหา','ฝี','ฝีหนอง','บาดแผล','แผลถลอก','ไหม้','แมลงกัด','สัตว์กัด','แผลในปาก','ปวดฟัน','ตาแดง','ตากุ้งยิง','หูอักเสบ','นอนไม่หลับ','วิตกกังวล','เครียด','ปวดประจำเดือน','ตกขาว'];
const inScope = conditions32.some(c => chatInput.toLowerCase().includes(c.toLowerCase()));
const outOfScopeHealth = ['เบาหวาน','diabetes','ความดัน','มะเร็ง','cancer','หัวใจ','ไตวาย','ตับแข็ง','hiv','เอดส์','ซึมเศร้า','จิตเวช','กระดูกพรุน','วัณโรค','ตั้งครรภ์','ครรภ์','ผ่าตัด','เคมีบำบัด','ท่องเที่ยว','หวย','การเมือง','เลือกตั้ง','ดูหนัง','เล่นเกม','ขอเพลง'];
const clearlyOutOfScope = outOfScopeHealth.some(kw => chatInput.toLowerCase().includes(kw.toLowerCase()));
const inActiveScreening = /🩺\s*ข้อ\s*\d+/i.test(chatInput) || chatInput.includes('[CHAT_HISTORY]');
const maybeOutOfScope = chatInput.length > 5 && !inScope && !inActiveScreening && !chatInput.includes('[PROFILE]') && !chatInput.match(/^(สวัสดี|hello|hi|เริ่ม)/i);
let hints = [];
let hints = [];
if (genderMismatch) hints.push('[SYSTEM_HINT] ผู้ป่วยเพศชาย ถามอาการผู้หญิง — ถามว่ากำลังถามแทน แม่/ภรรยา/น้องสาว/พี่สาว ใช่ไหม แล้วเก็บประวัติของบุคคลนั้น');
if (genderMismatchM) hints.push('[SYSTEM_HINT] ผู้ป่วยเพศหญิง ถามอาการผู้ชาย — ถามว่ากำลังถามแทน สามี/พ่อ/พี่ชาย/น้องชาย ใช่ไหม');
if (clearlyOutOfScope || maybeOutOfScope) hints.push('[SYSTEM_HINT] คำถามนอก 32 อาการบัตรทอง — ห้ามตอบ ห้ามใช้ medical_kb ให้ปฏิเสธตามข้อความใน prompt เท่านั้น');
const stateMatch = chatInput.match(/\[CHAT_STATE\][^\n]*ข้อ\s*(\d+)/);
if (stateMatch) {
  const nextQ = Number(stateMatch[1]);
  hints.push(`[SYSTEM_HINT] บังคับจากระบบ: ต้องเริ่มตอบด้วย "🩺 ข้อ ${nextQ}:" เท่านั้น ห้ามถามข้อ 1-${nextQ - 1} ซ้ำ`);
} else {
  const hdrRe = /🩺\s*ข้อ\s*(\d+)\s*[:：]/g;
  const askedNums = [];
  let hm;
  while ((hm = hdrRe.exec(chatInput)) !== null) askedNums.push(Number(hm[1]));
  if (askedNums.length > 0) {
    const max = Math.max(...askedNums);
    hints.push(`[SYSTEM_HINT] ถามไปแล้วถึงข้อ ${max} — ต้องถามข้อ ${max + 1} ต่อไปเท่านั้น`);
  }
}
if (!chatInput.includes('[CHAT_HISTORY]')) {
  hints.push('[SYSTEM_HINT] อ่าน memory + ข้อความล่าสุดก่อนถาม — ห้ามถามซ้ำ');
}
return [{ json: { chatInput: chatInput + (hints.length ? '\n\n' + hints.join('\n') : ''), sessionId, userName, userGender } }];

const all = $input.first().json.data ?? $input.first().json;
const rows = Array.isArray(all) ? all : Object.values(all);
return rows.map((r, idx) => {
  const q = (r.Question || '').trim();
  const a = (r.Response || '').trim();
  return { json: { id: idx, text: `คำถาม: ${q}\n\nคำตอบ: ${a}`, metadata: { source: 'train.json', row: idx, question: q.slice(0, 500) } } };
});
